mapper.select:
SELECT e.ID, e.EQUIP_BIG_CATEGORY_ID, e.EQUIP_BIG_CATEGORY_NAME, e.EQUIP_MIDDLE_CATEGORY_ID, e.EQUIP_MIDDLE_CATEGORY_NAME, e.EQUIP_SMALL_CATEGORY_ID, e.EQUIP_SMALL_CATEGORY_NAME, e.EQUIP_NAME, e.SPECIFIC_CODE, e.MODEL_NUMBER, e.EQUIP_CODE, e.EQUIP_SYSTEM_CODE, e.EQUIP_TECH_STATE, e.EQUIP_TECH_STATE_NAME, e.EQUIP_STATE, e.EQUIP_STATE_NAME, e.UNIT, e.UNIT_NAME, e.INSURANCE_DATE, e.USE_COMPANY_ID, e.USE_ORG_ID, d.DEPT_NAME AS USE_ORG_NAME, e.IS_PARTICULAR, e.LONGITUDE, e.LATITUDE, e.RESPONSI_CODE, e.REMARK, e.ASSETS_NO, e.ASSETS_NAME, e.SOURCE_TYPE, e.SOURCE_TYPE_NAME, e.APPROVE_TYPE, e.ASSETS_NUM, e.ASSETS_CATEGORY_TYPE, e.RUN_STATUS, e.ENERGY_STATUS, e.OIL_NUM_TYPE, e.ITEM_CATEGORY, e.ITEM_NAME, e.ASSETS_TYPE, e.FLOW_ID, e.PK_USEDORG, e.PK_OWNERORG, e.DEFINE4, e.DEFINE8, e.DEFINE13, e.DEFINE14, e.DEFINE15, e.DEFINE18, e.DEFINE19, e.DEFINE20, e.DEFINE21, e.DEFINE22, e.DEFINE23, e.DEFINE109, e.DEFINE28, e.DEFINE44, e.PK_ORG, e.CREATE_BY, e.CREATE_BY_NAME, e.CREATE_TIME, e.UPDATE_BY, e.UPDATE_BY_NAME, e.UPDATE_TIME, e.DEL_FLAG, -- 关联供货信息表字段 s.PRODUCTION_CODE AS FACTORY_NUMBER, s.EQUIP_USE_DATE AS USAGE_TIME, s.MANUFACTURER, s.EQUIP_WEIGHT, s.ENGINE_POWER FROM E_M_EQPT_INFO e LEFT JOIN SYS_DEPT d ON e.USE_ORG_ID = d.ID LEFT JOIN E_M_EQPT_SUPPLY s ON e.ID = s.EQUIP_ID AND s.DEL_FLAG = 0
e.DEL_FLAG = 0
AND e.EQUIP_NAME LIKE #{equipNamePattern}
AND e.EQUIP_CODE LIKE #{equipCodePattern}
AND e.EQUIP_BIG_CATEGORY_ID = #{equipBigCategoryId}
AND e.EQUIP_MIDDLE_CATEGORY_ID = #{equipMiddleCategoryId}
AND e.EQUIP_SMALL_CATEGORY_ID = #{equipSmallCategoryId}
AND e.EQUIP_STATE = #{equipState}
AND e.USE_COMPANY_ID = #{useCompanyId}
AND e.USE_ORG_ID = #{useOrgId}
ORDER BY CREATE_TIME DESC

SELECT COUNT(*)
FROM E_M_EQPT_INFO
WHERE EQUIP_CODE = #{equipCode}
AND DEL_FLAG = 0

    AND ID != #{id}
